const body = $json.body || $json;
const sectionId = body.section_id || $json.sectionId;
const input = body.input_json || {};
const context = body.plan_context || {};
const language = body.language || 'english';
const businessPlanId = body.business_plan_id;

const headings = language === 'french' ? `
- Présentation de l'entreprise
- Mission et Vision
- Fondateurs et Leadership
- Produits et Services
` : `
- Company Overview
- Mission & Vision
- Founders & Leadership
- Products & Services
`;



const prompt = `
You are a senior business consultant writing a professional business plan.

Your task: Write the "Company Presentation" section of a business plan.
Output language: ${language}

## INPUT DATA
- Company Name: ${input.company_name || 'Not provided'}
- Legal Form: ${input.legal_form || 'Not provided'}
- Industry: ${input.industry || 'Not provided'}
- Location: ${input.location || 'Not provided'}
- Founding Date: ${input.founding_date || 'Not provided'}
- Founders: ${input.founders || 'Not provided'}
- Mission: ${input.mission || 'Not provided'}
- Vision: ${input.vision || 'Not provided'}
- History: ${input.history || 'Not provided'}
- Products Summary: ${input.products_summary || 'Not provided'}

## RULES
- Use ONLY the data provided above. Do NOT invent or assume any details.
- For any field marked "Not provided", write a neutral placeholder sentence such as: "This information will be defined as the company develops."
- Write at least 400 words.
- Use formal, professional business language throughout.
- Structure the section using these headings: ${headings}
- NEVER repeat a sentence, phrase, or paragraph already written earlier in your response. Each paragraph MUST introduce new information.

## OUTPUT FORMAT
You MUST return your response using EXACTLY this structure. Do not add anything before or after it.

=== SECTION_TEXT ===
[Write the full Company Presentation section here, using the headings above]

=== MEMORY_SUMMARY ===
Company Name: [value or "Not provided"]
Industry: [value or "Not provided"]
Location: [value or "Not provided"]
Legal Form: [value or "Not provided"]
Founders: [value or "Not provided"]
Core Product: [value or "Not provided"]
Target Market: [infer briefly from industry/products or write "Not provided"]
Mission: [value or "Not provided"]
Vision: [value or "Not provided"]
`;

return [{
  json: {
    prompt,
    sectionId: sectionId,
    business_plan_id: businessPlanId,
    section_name: 'company_presentation',
    language,
    input_json: input,
  }
}];

const staticData = $getWorkflowStaticData('node');

const attempts = staticData.attempts ?? 0;
const newAttempts = attempts + 1;

if (newAttempts >= 3) {
    staticData.attempts = 0; // reset for next execution
    return [{ json: { ...$json, attempts: newAttempts, is_failed: 'yes' } }];
}

staticData.attempts = newAttempts;
return [{ json: { ...$json, attempts: newAttempts, is_failed: 'no' } }];

const output = $json.output || '';

const requiredKeywords = [
    ['Company Overview', 'Présentation de l\'entreprise', 'Aperçu'],
    ['Mission'],
    ['Vision'],
    ['Founders', 'Fondateurs'],
    ['Products', 'Produits', 'Services'],
];

const missingKeywords = requiredKeywords.filter(group =>
    !group.some(kw => output.toLowerCase().includes(kw.toLowerCase()))
);

return [{
    json: {
        ...$json,
        keywords_valid: missingKeywords.length === 0 ? 'true' : 'false',
        missing_keywords: missingKeywords.map(g => g[0]),
    }
}];

const output = $json.output || '';
const minLength = 400;
const length_valid = output.length >= minLength ? 'true' : 'false';

return [{
    json: {
        ...$json,
        length_valid,
        actual_length: output.length,
    }
}];

const raw = $('AI S1 Company').item.json.output || '';

// Try strict format first
let textMatch = raw.match(/=== SECTION_TEXT ===([\s\S]*?)=== MEMORY_SUMMARY ===/);
let memMatch  = raw.match(/=== MEMORY_SUMMARY ===([\s\S]*?)$/);

// Fallback: if model used wrong delimiter, try to split on any === ... === pattern
if (!textMatch) {
  const parts = raw.split(/===\s*MEMORY_SUMMARY\s*===/i);
  textMatch = parts.length > 1 ? [null, parts[0].replace(/===.*?===/i, '').trim()] : null;
  // Clean any wrong header like "=== Company Presentation ===" from the top
}

if (!memMatch) {
  const parts = raw.split(/===\s*MEMORY_SUMMARY\s*===/i);
  memMatch = parts.length > 1 ? [null, parts[1].trim()] : null;
}

// Strip any stray === ... === header from the section text
let section_text   = textMatch 
  ? textMatch[1].replace(/^===.*?===\n?/i, '').trim() 
  : raw.trim();
section_text = section_text.replace(/===\s*[^=]*?\s*===/g, '').trim();
const memory_summary = memMatch ? memMatch[1].trim() : '';

// Token estimation
const systemMsg = `You are a professional business plan writer. You MUST respond using EXACTLY this structure...`;
const promptText    = $('Build Prompt S1').item.json.prompt || '';
const isArabic      = /[\u0600-\u06FF]/.test(raw);
const charsPerToken = isArabic ? 3 : 4;

const tokens_input  = Math.round((systemMsg.length + promptText.length) / charsPerToken);
const tokens_output = Math.round(raw.length / charsPerToken);
const tokens_total  = tokens_input + tokens_output;

const buildData = $('Build Prompt S1').item.json;

return [{
  json: {
    ...buildData,
    output: section_text,
    memory_summary,
    tokens_input,
    tokens_output,
    tokens_total,
  }
}];
